// 자동 생성 — engine/embed_models.py. face-api 모델 내장 + fetch 인터셉트
(function(){
const EMB = {"tiny_face_detector_model-weights_manifest.json": {"json": true, "b64": ""}, "tiny_face_detector_model-shard1": {"json": false, "b64": ""}, "face_landmark_68_model-weights_manifest.json": {"json": true, "b64": ""}, "face_landmark_68_model-shard1": {"json": false, "b64": ""}};

function b64buf(b64){ const s=atob(b64); const u=new Uint8Array(s.length);
  for(let i=0;i<s.length;i++) u[i]=s.charCodeAt(i); return u.buffer; }
const orig = window.fetch ? window.fetch.bind(window) : null;
window.fetch = function(url, opts){
  const u = String(url && url.url ? url.url : url);
  for (const name in EMB){
    if (u.endsWith(name)){
      const e = EMB[name];
      const buf = b64buf(e.b64);
      const type = e.json ? "application/json" : "application/octet-stream";
      return Promise.resolve(new Response(buf, {status:200, headers:{"Content-Type":type}}));
    }
  }
  if (orig) return orig(url, opts);
  return Promise.reject(new Error("fetch unavailable: " + u));
};
})();
